using UnityEngine;
using UnityEditor;
using UnityEditor.SceneManagement;
public class Script {
  public static object Main() {
    var sb = new System.Text.StringBuilder();

    var spindle = GameObject.FindFirstObjectByType<CNC2SpindleController>();
    if (spindle == null) return "CNC2SpindleController not found";

    var so = new SerializedObject(spindle);
    so.Update();

    // Print all serialized fields to confirm what is currently stored
    sb.AppendLine("=== BEFORE ===");
    string[] fields = {
      "_xMoveSpeed","_xMin","_xMax",
      "_yMoveSpeed","_yMin","_yMax",
      "_zMoveSpeed","_zMin","_zMax",
      "_rotationAxis",
      "_meche","_spindlFinal","_spindleHolder","_cncCutter"
    };
    foreach (var f in fields) {
      var p = so.FindProperty(f);
      if (p == null) { sb.AppendLine(f + " : NOT FOUND"); continue; }
      string val = p.propertyType == SerializedPropertyType.ObjectReference
        ? (p.objectReferenceValue != null ? p.objectReferenceValue.name : "null")
        : p.type == "Vector3" ? p.vector3Value.ToString("F5")
        : p.floatValue.ToString("F6");
      sb.AppendLine(f + " = " + val);
    }

    // --- Apply correct limits ---
    void SetF(string name, float v) {
      var p = so.FindProperty(name);
      if (p != null) p.floatValue = v;
    }
    void SetV3(string name, Vector3 v) {
      var p = so.FindProperty(name);
      if (p != null) p.vector3Value = v;
    }
    void SetObj(string name, Object obj) {
      var p = so.FindProperty(name);
      if (p != null) p.objectReferenceValue = obj;
    }

    // X axis  (spindleHolder local X)
    SetF("_xMoveSpeed", 0.02f);
    SetF("_xMin",       0.0044f);
    SetF("_xMax",       0.06139f);

    // Y axis  (spindleFinal local Z = depth)
    SetF("_yMoveSpeed", 0.002f);
    SetF("_yMin",       -0.02f);     // deepest (most negative)
    SetF("_yMax",       -0.01602f);  // lifted

    // Z axis  (cncCutter local Z)
    SetF("_zMoveSpeed", 3.0f);
    SetF("_zMin",       -7f);
    SetF("_zMax",        5f);

    // Rotation axis = Z (local forward = drill axis)
    SetV3("_rotationAxis", Vector3.forward);

    // Wire _cncCutter reference
    Transform cncCutter = spindle.transform.parent;
    while (cncCutter != null && cncCutter.name != "cncCutter") cncCutter = cncCutter.parent;
    if (cncCutter != null) SetObj("_cncCutter", cncCutter);

    // Wire _spindleHolder = the transform this script sits on
    SetObj("_spindleHolder", spindle.transform);

    // Wire _spindlFinal and _meche from children
    Transform spindleFinal = spindle.transform.Find("spindleFinal");
    if (spindleFinal == null) spindleFinal = spindle.transform.Find("spindlFinal");
    if (spindleFinal != null) {
      SetObj("_spindlFinal", spindleFinal);
      Transform meche = spindleFinal.Find("meche");
      if (meche != null) SetObj("_meche", meche);
    }

    so.ApplyModifiedProperties();

    // Print AFTER to confirm
    sb.AppendLine("\n=== AFTER ===");
    so.Update();
    foreach (var f in fields) {
      var p = so.FindProperty(f);
      if (p == null) { sb.AppendLine(f + " : NOT FOUND"); continue; }
      string val = p.propertyType == SerializedPropertyType.ObjectReference
        ? (p.objectReferenceValue != null ? p.objectReferenceValue.name : "null")
        : p.type == "Vector3" ? p.vector3Value.ToString("F5")
        : p.floatValue.ToString("F6");
      sb.AppendLine(f + " = " + val);
    }

    EditorSceneManager.SaveOpenScenes();
    sb.AppendLine("\nScene saved.");
    return sb.ToString();
  }
}
